var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아아.","JPN":"ああ。","ENG":" Ah.","TWN":"啊啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"사장님에게 인정 받아 이렇게 둘만의 자리에 앉게 되다니. 정말 꿈만 같아요.","JPN":"社長に認められてこうして二人きりで居られる日が来るなんて、夢のようです。","ENG":" Finally, I've earned your approval. I feel as if I'm dreaming, having private time with you like this.","TWN":"我竟然可以得到老闆的認可，和您面對面單獨相處，我是在作夢嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"누군가는 절 범죄자, 악당이라고 부르겠지만......","JPN":"私のことを犯罪者、悪党と呼ぶ人もいますが……","ENG":" Some people call me a criminal, a villainess.","TWN":"雖然有人會說我是反派、是罪犯……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이런 일련의 과정이 있었기에 사장님을 만날 수 있었던 거죠. 그렇지 않나요?","JPN":"その一連の過程があったからこそ、社長に出会えたのです。そう思いませんか？","ENG":" But if I wasn't one, I would never have met you. Don't you agree?","TWN":"但正是因爲有着這一系列的經歷，我才能夠遇到老闆，不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"운명이란 건 참 얄궂고, 비과학적이고...... 사랑스럽네요.","JPN":"運命というのは実に意地悪で非科学的なもので……愛しいものですね。","ENG":" The Fate is so twisted, unscientific, and... lovely.","TWN":"命運真是愛捉弄人，無法用科學去解釋......但又很可愛！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후훗, 이 종신계약이 어떤 의미인지도 알고 있어요.","JPN":"フフッ、この終身契約がどういう意味なのか知っていますよ。","ENG":" Ho ho. I understand what lifetime contract means.","TWN":"呼～我知道這份合同代表着什麼意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"실은 더 긴밀한 관계를 원하지만, 사회적인 지위 때문에 저와의 친분을 공개적으로 드러내기 어려우신 거죠?","JPN":"本当はより緊密な関係を望んでいるものの、社会的地位のせいで私との親交を公にすることが難しいだけですよね？","ENG":" You want a more intimate relationship with me, but you can't afford to make it public because of your social stature, can you?","TWN":"我是想要更緊密的關係，但礙於老闆的社會地位，應該不方便公開與我的關係吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"걱정마세요. 저는 정말 이해심이 많은 여자랍니다.","JPN":"心配しないでくださいね。私はとても理解のある女なんです。","ENG":" Don't worry. I'm a very understanding woman.","TWN":"請放心，我一直是個善解人意的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당신이 어쩔 수 없는 이유로 제게 비수를 꽂는다 해도, 전 당신을 의심하지 않겠어요.","JPN":"あなたがやむを得ない理由で私を悲しませたとしても、私はあなたを疑いません。","ENG":" Even if you attack me because you have to, I won't hate you.","TWN":"就算您捅我一刀，我也相信您一定是逼不得已的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"전 당신의 진심을 보았고, 그 마음이 변치 않으리란 걸 누구보다 잘 알고 있으니까요.","JPN":"私はあなたの本音を知っていて、その気持ちが変わらないということを誰よりもよく理解しているのです。","ENG":" I've seen your sincerity. I know you'll never change your mind about me, no matter what.","TWN":"我明白您的真心，我知道您是絕對不會變心的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"누구보다도, 당신을, 이해하고 있다고요. 아시겠죠? 알고 계시죠? 네?","JPN":"誰よりも、あなたを、理解しているのです。わかりますか？　わかっていますよね？　そうでしょう？","ENG":" I understand you better than anyone else does. Got it? You already know that, right? Riiiight?","TWN":"我比任何人都理解您，您知道吧？不知道？哎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};